// сортировка), нужно и для GET-формы фильтров, и для ссылок сортировки колонок.
type PerfFilter struct {
	Period      string
	Environment string
	Sort        string
}

// perfListSortURL — ссылка на список с заданной сортировкой, сохраняя период и
// окружение фильтра (клик по заголовку колонки).
func perfListSortURL(projectID int64, f PerfFilter, sort string) string {
	q := url.Values{}
	if f.Period != "" {
		q.Set("period", f.Period)
	}
	if f.Environment != "" {
		q.Set("environment", f.Environment)
	}
	q.Set("sort", sort)
	return performancePath(projectID) + "?" + q.Encode()
}

// formatDurationUS форматирует длительность из микросекунд человекочитаемо:
// µs → ms → s. Перцентили и Apdex — колонки таблицы.
func formatDurationUS(us uint32) string {
	switch {
	case us == 0:
		return "0"
	case us < 1000:
		return strconv.FormatUint(uint64(us), 10) + "µs"
	case us < 1_000_000:
		return strconv.FormatFloat(float64(us)/1000, 'f', 1, 64) + "ms"
	default:
		return strconv.FormatFloat(float64(us)/1_000_000, 'f', 2, 64) + "s"
	}
}

// formatThroughput — транзакций в минуту с одним знаком после запятой.
func formatThroughput(perMin float64) string {
	return strconv.FormatFloat(perMin, 'f', 1, 64) + "/min"
}

// formatFailureRate — доля ошибок (0..1) в процентах с одним знаком.
func formatFailureRate(rate float64) string {
	return strconv.FormatFloat(rate*100, 'f', 1, 64) + "%"
}

// formatApdex — Apdex-балл (0..1) с двумя знаками.
func formatApdex(score float64) string {
	return strconv.FormatFloat(score, 'f', 2, 64)
}

